package IAppController

import (
	"strings"
	"testing"

	"github.com/ethereum/go-ethereum/accounts/abi"
	"github.com/ethereum/go-ethereum/common/hexutil"
)

// wantAppUpgradedTopic0 is the keccak of the AppUpgraded event signature for
// the deployed v1.5.x AppController:
//
//	AppUpgraded(address,uint256,(((bytes32,string)[],uint32),bytes,bytes,(string[],string[],(string,string)[],(string,string)[],string)))
//
// If this changes, the on-chain ABI drifted and this binding must be
// regenerated — otherwise FilterAppUpgraded matches nothing and the KMS
// returns "Release not found" for every app.
const wantAppUpgradedTopic0 = "0x5e69c7a791a6bb49176e938952d5ebf7b706e399ca57a98ea0de48d5ed248408"

func TestAppUpgradedTopic0MatchesDeployedABI(t *testing.T) {
	parsed, err := abi.JSON(strings.NewReader(IAppControllerMetaData.ABI))
	if err != nil {
		t.Fatalf("parse ABI: %v", err)
	}
	ev, ok := parsed.Events["AppUpgraded"]
	if !ok {
		t.Fatal("AppUpgraded event missing from ABI")
	}
	if got := ev.ID.Hex(); got != wantAppUpgradedTopic0 {
		t.Fatalf("AppUpgraded topic0 mismatch:\n got  %s\n want %s\n(binding ABI drifted from the deployed AppController; regenerate it)", got, wantAppUpgradedTopic0)
	}
}

// realAppUpgradedLogData is the non-indexed data of a real AppUpgraded event
// emitted by the v1.5.1 AppController on Sepolia (app
// 0xD0236d0731428DF5b5e5FbC8B5f95237989A0818, block 11096105). It guards
// against ABI shape drift that would compile fine but fail to decode live
// events (the failure mode that returned "Release not found").
const realAppUpgradedLogData = ""

func TestDecodeRealAppUpgradedEvent(t *testing.T) {
	parsed, err := abi.JSON(strings.NewReader(IAppControllerMetaData.ABI))
	if err != nil {
		t.Fatalf("parse ABI: %v", err)
	}
	ev := parsed.Events["AppUpgraded"]
	data, err := hexutil.Decode(realAppUpgradedLogData)
	if err != nil {
		t.Fatalf("decode fixture: %v", err)
	}
	out := map[string]interface{}{}
	if err := ev.Inputs.NonIndexed().UnpackIntoMap(out, data); err != nil {
		t.Fatalf("failed to decode real AppUpgraded event (ABI shape drift): %v", err)
	}
	if _, ok := out["release"]; !ok {
		t.Fatal("decoded event missing release field")
	}
	// rmsReleaseId is uint256 in v1.5.x (was bytes32); confirm it round-trips
	// (the real fixture's value is 0, a valid production case).
	if _, ok := out["rmsReleaseId"]; !ok {
		t.Fatal("decoded event missing rmsReleaseId field")
	}
}
